import{_ as i}from"./chunks/ideas-panel.yVDzxnSx.js";import{_ as s}from"./chunks/script-editor.ngC1KYbm.js";import{_ as a}from"./chunks/discover-search.kdi1S6L1.js";import{_ as t}from"./chunks/resources-search.DGzWXay7.js";import{_ as o}from"./chunks/audio-sections.BTOGBP1S.js";import{_ as r}from"./chunks/episodes-panel.xrb5a5RP.js";import{_ as l}from"./chunks/proposals-panel.DR2TeORO.js";import{_ as n,o as d,c,ag as p}from"./chunks/framework._658-eYr.js";const h="/CRAFT/assets/image-generate.Dr6CZzqr.png",u="/CRAFT/assets/music-generate.DCh0K4Mg.png",v="/CRAFT/assets/voice-train.czC3inFQ.png",g="/CRAFT/assets/voice-picker.DU9SPjHd.png",G=JSON.parse(`{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"CRAFT Studio","text":"The Complete YouTube Content Studio","tagline":"AI scripts. Competitive research. Audio production. GPU-accelerated generation. 14 media sources. One studio.","actions":[{"theme":"brand","text":"Get Started","link":"/guide/"},{"theme":"alt","text":"Mobile App","link":"/mobile/"},{"theme":"alt","text":"View on GitHub","link":"https://github.com/VibeSmiths/VideoIdeas"}]},"features":[{"icon":"✍️","title":"AI Script Writing","details":"Write, revise, polish, fact-check, and humanize scripts with Claude, Gemini, or local Ollama models in your channel's voice."},{"icon":"🔍","title":"YouTube Research","details":"Search YouTube with outlier detection, channel deep dives, earnings estimates, and competitive analysis."},{"icon":"🎧","title":"Audio Production","details":"4 TTS providers (Edge free, ElevenLabs, OpenAI, OpenedAI Speech local). AI background music generation with MusicGen."},{"icon":"🖼️","title":"AI Image Generation","details":"Generate thumbnails and B-roll with ComfyUI + Stable Diffusion. Channel-aware prompts with AI assist."},{"icon":"🎵","title":"AI Music Generation","details":"Create instrumental background tracks from text prompts with MusicGen. Bind to projects or standalone download."},{"icon":"🎬","title":"8-Stage Pipeline","details":"Automated content pipeline — Research, Script, Storyboard, Assets, Compositing, Export, Review, Publish — orchestrated by 14 AI agents with quality gates."},{"icon":"📋","title":"AI Proposals","details":"AI-scored content proposals with trend analysis, timeliness signals, and approval workflows before entering production."},{"icon":"🚀","title":"GPU-Accelerated","details":"5 optional GPU services — Ollama, OpenedAI Speech, MusicGen, ComfyUI, RVC voice cloning. All self-hosted."},{"icon":"📚","title":"Resource Library","details":"Search 14 royalty-free sources for video, image, audio, and reference material with auto-attribution."},{"icon":"📱","title":"Mobile Companion","details":"Android app for ideas, scripts, and YouTube research on the go. Connects over local network."},{"icon":"📤","title":"Multi-Platform Publishing ✨","details":"Coming Soon — Publish directly to YouTube, TikTok, Facebook, and X from a single workflow."}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}`),m={name:"index.md"};function f(b,e,w,y,A,k){return d(),c("div",null,[...e[0]||(e[0]=[p('<div class="craft-showcase"><div class="badge-row"><img src="https://img.shields.io/badge/Docs-Live-0d9488?logo=vitepress&amp;logoColor=white" alt="Docs"><img src="https://img.shields.io/badge/TypeScript-strict-0d9488?logo=typescript&amp;logoColor=white" alt="TypeScript"><img src="https://img.shields.io/badge/React-18-0d9488?logo=react&amp;logoColor=white" alt="React"><img src="https://img.shields.io/badge/Docker-compose-0d9488?logo=docker&amp;logoColor=white" alt="Docker"><img src="https://img.shields.io/badge/AI-Claude_%2B_Gemini_%2B_Ollama-0d9488?logo=anthropic&amp;logoColor=white" alt="AI"><img src="https://img.shields.io/badge/TTS-300%2B_Voices-0d9488" alt="TTS"><img src="https://img.shields.io/badge/Pipeline-8_Stages-0d9488?logo=nats&amp;logoColor=white" alt="Pipeline"><img src="https://img.shields.io/badge/Agents-14-0d9488?logo=anthropic&amp;logoColor=white" alt="Agents"><img src="https://img.shields.io/badge/GPU-5_Services-0d9488?logo=nvidia&amp;logoColor=white" alt="GPU"><img src="https://img.shields.io/badge/Mobile-Android-0d9488?logo=android&amp;logoColor=white" alt="Mobile"></div><h2 id="numbers-that-matter" tabindex="-1">Numbers That Matter <a class="header-anchor" href="#numbers-that-matter" aria-label="Permalink to &quot;Numbers That Matter&quot;">​</a></h2><div class="stats-row"><div class="stat-card"><div class="stat-number">14</div><div class="stat-label">Media Sources</div></div><div class="stat-card"><div class="stat-number">300+</div><div class="stat-label">TTS Voices</div></div><div class="stat-card"><div class="stat-number">14</div><div class="stat-label">AI Agents</div></div><div class="stat-card"><div class="stat-number">9</div><div class="stat-label">Pipeline Workers</div></div></div><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><div class="steps"><div class="step"><div class="step-number">1</div><div class="step-content"><strong>Create a Channel</strong><p>Define your channel&#39;s character, voice, and niche. The AI adapts to your persona.</p></div></div><div class="step"><div class="step-number">2</div><div class="step-content"><strong>Generate Ideas</strong><p>AI brainstorms based on your topics, or save inspiration from YouTube research.</p></div></div><div class="step"><div class="step-number">3</div><div class="step-content"><strong>Run the Pipeline</strong><p>AI agents research, write, storyboard, and compose your video through 8 stages with automated quality gates.</p></div></div><div class="step"><div class="step-number">4</div><div class="step-content"><strong>Review &amp; Publish</strong><p>Producer agent scores each stage. Review the final cut, approve, and publish — all from one dashboard.</p></div></div></div><h2 id="feature-highlights" tabindex="-1">Feature Highlights <a class="header-anchor" href="#feature-highlights" aria-label="Permalink to &quot;Feature Highlights&quot;">​</a></h2><div class="feature-section"><div class="feature-text"><h3>Idea Generation &amp; Management</h3><p>Generate ideas with AI tuned to your channel&#39;s personality. Save inspiration from YouTube Discover. Expand, edit, and convert ideas into full scripts with one click.</p><ul><li>AI brainstorming with channel context</li><li>Import from YouTube research with metadata</li><li>Search, sort, filter by type (shorts/long)</li><li>Convert to script with enrichment data</li></ul></div><div class="feature-screenshot"><img src="'+i+'" alt="Ideas Panel"></div></div><div class="feature-section reverse"><div class="feature-text"><h3>AI Script Editor</h3><p>Write scripts in your channel&#39;s character voice. AI-powered revision, polishing, and fact-checking keep your content accurate and natural.</p><ul><li>Write with Voice — AI drafts in character</li><li>Revise with custom instructions</li><li>Fact Check — verify claims with sources</li><li>Humanize — detect and rewrite AI-sounding text</li><li>Status workflow: Draft → Review → Final</li></ul></div><div class="feature-screenshot"><img src="'+s+'" alt="Script Editor"></div></div><div class="feature-section"><div class="feature-text"><h3>YouTube Discover</h3><p>Research trending content with yt-dlp-powered search. No API key needed for basic search. Progressive loading fetches more results as you scroll.</p><ul><li>Filter by duration, date, subscriber cap</li><li>Outlier detection — find viral hits (5x/10x/50x avg)</li><li>Channel deep dive with earnings estimates</li><li>Compare up to 3 channels side-by-side</li><li>Save any video as an idea with full metadata</li></ul></div><div class="feature-screenshot"><img src="'+a+'" alt="Discover Search"></div></div><div class="feature-section reverse"><div class="feature-text"><h3>Resource Library</h3><div class="feature-stats"><span class="feature-stat">14 Sources</span><span class="feature-stat">4 Media Types</span><span class="feature-stat">Auto Attribution</span></div><p>Search across Pexels, Pixabay, Unsplash, NASA, Wikimedia Commons, Met Museum, Europeana, and more. Preview inline and download with automatic attribution tracking.</p><ul><li>Video, image, audio, and reference search</li><li>Grid &amp; list views with hover preview</li><li>Source and license filtering</li><li>Tag-based search suggestions from scripts</li><li>Upload your own media with drag-and-drop</li></ul></div><div class="feature-screenshot"><img src="'+t+'" alt="Resource Library"></div></div><div class="feature-section"><div class="feature-text"><h3>AI Image Generation</h3><p>Generate thumbnails and B-roll with ComfyUI and Stable Diffusion. Channel-aware AI prompts get you started fast.</p><ul><li>Text-to-image with multiple checkpoint support</li><li>Aspect ratio presets (1:1, 16:9, 9:16, 4:3, 3:4)</li><li>Generation metadata saved per image (prompt, settings)</li><li>Click-to-zoom preview with full parameter display</li><li>Per-channel gallery with download and delete</li></ul></div><div class="feature-screenshot"><img src="'+h+'" alt="AI Image Generation"></div></div><div class="feature-section reverse"><div class="feature-text"><h3>Audio Production</h3><p>Full audio pipeline from TTS to final mix. 300+ voices with screenplay-aware section parsing. Background music layering and SFX insertion.</p><ul><li>4 TTS providers — Edge (free), ElevenLabs, OpenAI, OpenedAI Speech</li><li>Upload your own voiceover and split at timestamps</li><li>SFX sections between speech sections</li><li>Background music with volume, fade, and loop controls</li><li>RVC voice cloning for custom voice conversion</li></ul></div><div class="feature-screenshot"><img src="'+o+'" alt="Audio Production"></div></div><div class="feature-section"><div class="feature-text"><h3>AI Music Generation</h3><p>Create instrumental background tracks from text prompts with Meta&#39;s MusicGen. Bind directly to audio projects or download standalone.</p><ul><li>Text-to-music with genre, mood, and instrument control</li><li>Adjustable duration (10s–30s)</li><li>AI-assisted prompt generation</li><li>Attach to audio projects or standalone download</li><li>Prompt tips for best results</li></ul></div><div class="feature-screenshot"><img src="'+u+'" alt="AI Music Generation"></div></div><div class="feature-section reverse"><div class="feature-text"><h3>Voice Training (RVC)</h3><p>Clone any voice with RVC v2. Upload audio samples, browse community models from HuggingFace, and convert TTS output to sound like anyone.</p><ul><li>Upload voice models (.pth) or training audio (.zip)</li><li>Browse and install HuggingFace voice models</li><li>RVC voice conversion on TTS output</li><li>GPU-accelerated inference</li><li>Preview voices before applying</li></ul></div><div class="feature-screenshot"><img src="'+v+'" alt="Voice Training (RVC)"></div></div><div class="feature-section"><div class="feature-text"><h3>Episode Pipeline</h3><div class="feature-stats"><span class="feature-stat">8 Stages</span><span class="feature-stat">14 AI Agents</span><span class="feature-stat">Quality Gates</span></div><p>Orchestrate complete video production through 8 stages — each powered by a specialized AI agent with automated producer review and feedback loops.</p><ul><li>Research → Script → Storyboard → Assets → Compositing → Export → Review → Publish</li><li>Producer agent scores each stage 1-10 with revision feedback</li><li>Run full pipeline or individual stages</li><li>Upstream issue detection and soft recovery</li><li>Real-time progress via SSE</li></ul></div><div class="feature-screenshot"><img src="'+r+'" alt="Episode Pipeline"></div></div><div class="feature-section reverse"><div class="feature-text"><h3>AI Proposals</h3><p>AI-scored content proposals analyze trends, channel history, and audience signals to surface your best next video topic. Review, approve, and feed directly into the production pipeline.</p><ul><li>0-100 confidence scoring with trend signals</li><li>Timeliness indicators for time-sensitive topics</li><li>Approve to convert into production-ready ideas</li><li>Powered by Curator and Trend Analyst agents</li></ul></div><div class="feature-screenshot"><img src="'+l+'" alt="AI Proposals"></div></div><div class="feature-section"><div class="feature-text"><h3>Channel Settings &amp; Voice</h3><p>Configure your channel&#39;s personality, voice, and analytics. The AI Character Creator generates a full persona from a few questions.</p><ul><li>AI Character Creator — tone, quirks, audience</li><li>Voice picker with 300+ voices and preview</li><li>Stability and similarity tuning for ElevenLabs</li><li>RPM presets for earnings estimates</li><li>MCP server management</li></ul></div><div class="feature-screenshot"><img src="'+g+'" alt="Settings Panel"></div></div><h2 id="open-source-self-hosted" tabindex="-1">Open Source &amp; Self-Hosted <a class="header-anchor" href="#open-source-self-hosted" aria-label="Permalink to &quot;Open Source &amp; Self-Hosted&quot;">​</a></h2><div class="self-hosted"><div class="self-hosted-content"><p class="self-hosted-pitch">Your data stays on your machine. Runs entirely in Docker with no external dependencies beyond your API keys.</p><div class="self-hosted-code"><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span></code></pre></div></div><div class="self-hosted-links"><a href="./guide/setup">Setup Guide →</a></div></div></div><h2 id="powered-by" tabindex="-1">Powered By <a class="header-anchor" href="#powered-by" aria-label="Permalink to &quot;Powered By&quot;">​</a></h2><div class="powered-section"><div class="powered-group"><div class="powered-label">Frontend</div><div class="tech-stack"><span class="tech-badge">React</span><span class="tech-badge">TypeScript</span><span class="tech-badge">Tailwind</span><span class="tech-badge">Zustand</span></div></div><div class="powered-group"><div class="powered-label">Backend</div><div class="tech-stack"><span class="tech-badge">Express</span><span class="tech-badge">Docker</span><span class="tech-badge">PostgreSQL</span><span class="tech-badge">yt-dlp</span><span class="tech-badge">ffmpeg</span></div></div><div class="powered-group"><div class="powered-label">Pipeline</div><div class="tech-stack"><span class="tech-badge">NATS JetStream</span><span class="tech-badge">Agent SDK</span><span class="tech-badge">Redis</span><span class="tech-badge">9 Workers</span></div></div><div class="powered-group"><div class="powered-label">AI &amp; Audio</div><div class="tech-stack"><span class="tech-badge">Claude</span><span class="tech-badge">Gemini</span><span class="tech-badge">Ollama</span><span class="tech-badge">Edge TTS</span><span class="tech-badge">OpenedAI Speech</span><span class="tech-badge">MusicGen</span></div></div><div class="powered-group"><div class="powered-label">GPU Services</div><div class="tech-stack"><span class="tech-badge">ComfyUI</span><span class="tech-badge">Stable Diffusion</span><span class="tech-badge">RVC</span></div></div></div></div>',1)])])}const F=n(m,[["render",f]]);export{G as __pageData,F as default};
